#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define grep(a,b,c) for(int c=a.head[b];c;c=a.nxt[c])
#define Clear(a) memset(a,0,sizeof(a))
using namespace std;
const int N=3005,M=4500005,INF=0x7fffffff;
inline int read()
{
	int res=0;char ch=getchar();bool flag=0;
	while(ch<'0'||ch>'9')flag=(ch=='-'),ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();
	return flag ? -res : res ;
}

//

struct Graph{int head[M],nxt[M],des[M],cap[M],cnt;
	inline void ins(int x,int y,int z){des[++cnt]=y;cap[cnt]=z;nxt[cnt]=head[x];head[x]=cnt;}}a;
int b[N],dep[N];bool A[N],vis[N];int que[N],H,T,s,t;
inline bool bfs()
{
	Clear(dep);dep[que[H=T=1]=s]=1;dep[s]=1;while(H<=T)
		{int u=que[H++];grep(a,u,i){int v=a.des[i];if(a.cap[i]&&!vis[v])dep[que[++T]=v]=dep[u]+1;}}return dep[t];
}
int dfs(int u,int in)
{
	if(u==t)return in;vis[u]=1;int out=0;grep(a,u,i)
	{
		int v=a.des[i];if(dep[v]==dep[u]+1&&a.cap[i])
			{int tmp=dfs(v,min(a.cap[i],in));a.cap[i]-=tmp;a.cap[i^1]+=tmp;in-=tmp;out+=tmp;}if(!in)break;
	}
	if(!out)dep[u]=0;return out;
}
inline int dinic(int u,int v){s=u;t=v;int res=0;while(bfs())res+=dfs(s,INF);return res;}

//

inline bool check(int q){int res=0;while(q){res+=(q&1);q=q>>1;}return res&1;}
inline bool Check(int q){while(q>9)q/=10;return (q==9);}
inline void mian()
{
	Clear(a.head);Clear(vis);a.cnt=1;int nA=read(),nB=read(),M=read();rep(1,nA,i)A[i]=read()&1;
	rep(1,nB,i)b[i]=read();rep(1,nB,i)if(b[i]&1)rep(1,nB,j)if(!(b[j]&1)&&!check(b[i]|b[j]))a.ins(i,j,1),a.ins(j,i,0);
	rep(1,nB,i){if(b[i]&1)a.ins(nB+1,i,1),a.ins(i,nB+1,0);else a.ins(i,nB+2,1),a.ins(nB+2,i,0);}
	int res=nB-dinic(nB+1,nB+2);res+=Check(res);printf("%d\n",res);
}
int main(){int T=read();while(T--)mian();return 0;}
